class GroceryStore:
    flat_discount = 0         # Class attribute for discount percentage
    min_purchase_amount = 200 # Class attribute for minimum purchase amount

    def __init__(self):
        self.inventory = {}     # Instance attribute for storing items

    def add_item(self, item_name, quantity):
        if item_name in self.inventory:
            self.inventory[item_name] += quantity
        else:
            self.inventory[item_name] = quantity

    def remove_item(self, item_name):
        if item_name in self.inventory:
            del self.inventory[item_name]
        else:
            print("Item not found")

    def checkout(self):
        total = sum(quantity * 100 for quantity in self.inventory.values())  # Assuming each item costs Rs. 100
        if total < GroceryStore.min_purchase_amount:
            print("Minimum purchase amount not met for discount")
            return

        if total >= 200:
            discount_amount = (total * GroceryStore.flat_discount) / 100
            total -= discount_amount

        print(f"Final amount after discount: Rs. {total}")

    def display_inventory(self):
        return {item: quantity for item, quantity in self.inventory.items()}

    @classmethod
    def set_discount(cls, new_discount):
        cls.flat_discount = new_discount

# Do not modify the code below. This function will be called during testing.
def default_test():
    store = GroceryStore()
    store.add_item("Apples", 10)
    store.add_item("Bananas", 5)
    store.remove_item("Bananas")
    store.set_discount(15)  # Set discount to 15%
    store.checkout()  # Should calculate total and apply discount if applicable
    print(store.display_inventory())
